SOROBAN_STATE_LIMIT.fixExample:
// Problem: Storing too much data
#[contracttype]
pub struct LargeData {
    items: Vec<String>, // Could grow beyond 64KB
}

// Solution 1: Use pagination and limits
#[contracttype]
pub struct PaginatedData {
    items: Vec<String>,
}

impl Contract {
    pub fn add_item(env: Env, item: String) -> Result<(), Error> {
        let mut data: PaginatedData = env.storage()
            .persistent()
            .get(&symbol_short!("data"))
            .unwrap_or(PaginatedData { items: vec![&env] });

        if data.items.len() >= 100 {
            return Err(Error::StorageFull);
        }

        data.items.push_back(item);
        env.storage().persistent().set(&symbol_short!("data"), &data);
        Ok(())
    }
}

// Solution 2: Use separate storage entries
impl Contract {
    pub fn set_user_balance(env: Env, user: Address, balance: i128) {
        // Each user gets their own storage entry
        env.storage().persistent().set(&user, &balance);
    }
}

