    env.storage()
        .persistent()
        .get(&symbol_short!("admin"))
        .unwrap() // Panics if admin not set!
}

// Solution 1: Use Result type
pub fn get_admin(env: Env) -> Result<Address, Error> {
    env.storage()
        .persistent()
        .get(&symbol_short!("admin"))
        .ok_or(Error::AdminNotSet)
}

