pub fn get_admin(env: Env) -> Address {
    env.storage()
        .persistent()
        .get(&symbol_short!("admin"))
        .unwrap_or_else(|| env.current_contract_address())
}

SOROBAN_OVERFLOW.fixExample:
// Problem: Unchecked arithmetic
pub fn add_balance(env: Env, user: Address, amount: i128) {
    let balance = get_balance(&env, &user);
    let new_balance = balance + amount; // Could overflow!
    set_balance(&env, &user, new_balance);
}

// Solution: Use checked arithmetic
pub fn add_balance(env: Env, user: Address, amount: i128) -> Result<(), Error> {
    let balance = get_balance(&env, &user);
    let new_balance = balance
        .checked_add(amount)
        .ok_or(Error::Overflow)?;
    set_balance(&env, &user, new_balance);
    Ok(())
}

// Or use saturating arithmetic if appropriate
pub fn add_balance(env: Env, user: Address, amount: i128) {
    let balance = get_balance(&env, &user);
    let new_balance = balance.saturating_add(amount);
    set_balance(&env, &user, new_balance);
}
